func Width(r rune) int {
	if w, ok := widths[r]; ok {
		return w
	} else {
		return 1
	}
}

func WidthString(s string) int {
	sum := 0
	for _, r := range []rune(s) {
		sum += Width(r)
	}
	return sum
}
